const API_BASE = "http://localhost:3000";

const api = {

  getHomeList: async () => {
    const res = await fetch(`${API_BASE}/movies`);
    const json = await res.json();

    return json; // 👈 NÃO mexe mais
  },

  getMovieInfo: async (movieId) => {
    const res = await fetch(`${API_BASE}/movies`);
    const json = await res.json();

    const allMovies = json.flatMap(i => i.items.results);

    return allMovies.find(m => m.id === movieId) || null;
  }

};

export default api;
